INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('Which of the following is a proper noun?', '["Philippines", "country", "city", "language"]', 'A', 'A proper noun names a specific person, place, or thing and is capitalized. "Philippines" is a proper noun; "country," "city," and "language" are common nouns.', 'English', 'Grammar', 'easy', 'secondary'),
('What is the plural form of "child"?', '["Children", "Childs", "Childes", "Child''s"]', 'A', '"Child" has an irregular plural: "children." It does not follow the regular pattern of adding -s or -es.', 'English', 'Grammar', 'easy', 'secondary'),
('Which sentence uses the passive voice?', '["The report was written by the secretary.", "The secretary wrote the report.", "The secretary is writing the report.", "The secretary has written the report."]', 'A', 'Passive voice: subject receives the action. "The report was written by the secretary" — "the report" (subject) receives the action "was written."', 'English', 'Grammar', 'medium', 'secondary'),
('What is the literary term for a story that teaches a moral lesson, often with animals as characters?', '["Fable", "Myth", "Legend", "Folktale"]', 'A', 'A fable is a short story, typically featuring animals with human characteristics, that conveys a moral lesson. Aesop''s Fables are classic examples.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which of the following is an example of onomatopoeia?', '["The bees buzzed in the garden.", "She was as brave as a lion.", "Time flies when you''re having fun.", "The wind was a howling wolf."]', 'A', '"Buzzed" is an onomatopoeic word — it imitates the sound bees make. It is an example of onomatopoeia.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What does the conjunction "although" signal in a sentence?', '["A contrast or concession", "A cause and effect", "A sequence in time", "An addition"]', 'A', '"Although" is a subordinating conjunction that introduces a contrast or concession: "Although it was raining, they continued playing."', 'English', 'Grammar', 'medium', 'secondary'),
('What is an "antonym"?', '["A word with the opposite meaning of another word", "A word with the same meaning as another word", "A word that sounds the same as another", "A word related to another in meaning"]', 'A', 'An antonym is a word that means the opposite of another word. For example, "hot" is an antonym of "cold."', 'English', 'Vocabulary', 'easy', 'secondary'),
('Which of the following correctly identifies an "abstract noun"?', '["Freedom", "Table", "Mountain", "Teacher"]', 'A', 'An abstract noun names an idea, quality, or state rather than a physical object. "Freedom" is abstract because it cannot be touched or seen.', 'English', 'Grammar', 'medium', 'secondary'),
('In which type of poem does every line begin with the same letter or word for emphasis?', '["Anaphora", "Haiku", "Sonnet", "Limerick"]', 'A', 'Anaphora is the repetition of a word or phrase at the beginning of successive clauses or verses for emphasis. It is common in speeches and poetry.', 'English', 'Literary Devices', 'hard', 'secondary'),
('What is the correct form: "Each of the students __ required to submit a project."', '["is", "are", "were", "have been"]', 'A', '"Each" is an indefinite pronoun that is always singular. The correct verb is "is" (Each of the students is required...).', 'English', 'Grammar', 'medium', 'secondary'),
('What does "denotation" mean?', '["The literal, dictionary meaning of a word", "The emotional associations of a word", "The origin of a word", "The grammatical category of a word"]', 'A', 'Denotation is the direct, literal meaning of a word as found in a dictionary. Connotation refers to the emotional or cultural associations.', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which figure of speech involves saying the opposite of what is meant?', '["Verbal irony", "Simile", "Metaphor", "Hyperbole"]', 'A', 'Verbal irony involves saying the opposite of what you mean, often for humor or emphasis. Sarcasm is a form of verbal irony.', 'English', 'Literary Devices', 'medium', 'secondary'),
('What is the correct comparative form of "good"?', '["Better", "Gooder", "More good", "Best"]', 'A', '"Good" has an irregular comparative form: better (comparative) and best (superlative). "Gooder" and "more good" are incorrect.', 'English', 'Grammar', 'easy', 'secondary'),
('What is the term for the introductory section of a story that establishes characters, setting, and background?', '["Exposition", "Rising action", "Climax", "Resolution"]', 'A', 'Exposition is the opening part of a story''s plot structure where the author introduces characters, setting, and the background needed to understand the story.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is a "homophone"?', '["Words that sound alike but have different meanings and spellings", "Words with opposite meanings", "Words with the same meaning", "Words with the same spelling but different meanings"]', 'A', 'Homophones are words that have the same pronunciation but different meanings and often different spellings (e.g., "to," "too," "two"; "their," "there," "they''re").', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which of the following contains a misplaced modifier?', '["She almost drove her children to school every day.", "She drove her children to school almost every day.", "Almost every day, she drove her children to school.", "She drove almost all of her children to school."]', 'A', '"She almost drove her children to school every day" misplaces "almost" — it implies she never quite drove them. The intended meaning requires "almost every day."', 'English', 'Writing', 'hard', 'secondary'),
('What is the literary term for the central struggle in a story?', '["Conflict", "Theme", "Climax", "Resolution"]', 'A', 'Conflict is the central struggle between opposing forces in a story. It drives the plot and can be external (vs. other characters, nature, society) or internal (vs. self).', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is a "pronoun"?', '["A word that takes the place of a noun", "A word that describes a noun", "A word that shows action", "A word that connects clauses"]', 'A', 'A pronoun replaces a noun to avoid repetition (e.g., he, she, it, they, we). "Maria studied; she passed the exam" — "she" replaces "Maria."', 'English', 'Grammar', 'easy', 'secondary'),
('What is the purpose of the "conclusion" paragraph in an essay?', '["To summarize the main points and restate the thesis", "To introduce new arguments", "To provide evidence for the thesis", "To define key terms"]', 'A', 'The conclusion paragraph wraps up the essay by restating the thesis (in different words), summarizing key points, and leaving the reader with a final thought.', 'English', 'Writing', 'easy', 'secondary'),
('What does "connotation" mean?', '["The emotional associations and implied meanings of a word beyond its literal definition", "The literal dictionary meaning", "The grammatical function of a word", "The origin of a word"]', 'A', 'Connotation refers to the cultural, emotional, or implied associations a word carries beyond its literal (denotative) meaning. For example, "home" connotes warmth and family.', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which of the following is a linking verb?', '["Seems", "Run", "Jump", "Think"]', 'A', 'A linking verb connects the subject to a subject complement (predicate noun or adjective). "Seems" is a linking verb: "She seems happy."', 'English', 'Grammar', 'medium', 'secondary'),
('What is an "oxymoron"?', '["A figure of speech combining contradictory terms", "An extreme exaggeration", "A comparison using like or as", "A reference to mythology"]', 'A', 'An oxymoron combines contradictory words to create a unique effect (e.g., "deafening silence," "living dead," "bittersweet").', 'English', 'Literary Devices', 'medium', 'secondary'),
('What is the correct past tense of "write"?', '["Wrote", "Writed", "Written", "Was writing"]', 'A', '"Write" is an irregular verb. Past tense: wrote. Past participle: written. ("I wrote the letter yesterday.")', 'English', 'Grammar', 'easy', 'secondary'),
('What is the term for hints in a text that help predict future events?', '["Foreshadowing", "Flashback", "Allusion", "Symbolism"]', 'A', 'Foreshadowing is a literary device where the author hints at events that will occur later in the story, creating suspense and building anticipation.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which word is spelled correctly?', '["Necessary", "Neccesary", "Necesary", "Neccessary"]', 'A', '"Necessary" is the correct spelling (one c, two s''s). A common mnemonic: one Collar, two Socks (1 C, 2 S).', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is a "gerund"?', '["A verb form used as a noun, ending in -ing", "A verb that shows past action", "An adjective modifying a noun", "A connecting word between clauses"]', 'A', 'A gerund is a verb form ending in -ing that functions as a noun in a sentence. Example: "Swimming is excellent exercise" — "swimming" is a gerund.', 'English', 'Grammar', 'medium', 'secondary'),
('What does it mean for a text to have "coherence"?', '["Ideas flow logically and are connected smoothly", "Every paragraph has the same length", "The text uses only formal language", "All sentences are short and simple"]', 'A', 'Coherence in writing means ideas are logically organized and flow smoothly. Transition words, pronouns, and repetition of key terms help create coherence.', 'English', 'Writing', 'medium', 'secondary'),
('What literary device involves the repetition of vowel sounds in nearby words?', '["Assonance", "Alliteration", "Consonance", "Onomatopoeia"]', 'A', 'Assonance is the repetition of vowel sounds in nearby words, creating internal rhyme and musical effect (e.g., "The rain in Spain stays mainly in the plain").', 'English', 'Literary Devices', 'medium', 'secondary'),
('What is the purpose of quotation marks?', '["To indicate direct speech or titles of short works", "To show emphasis on a word", "To introduce a list", "To separate independent clauses"]', 'A', 'Quotation marks are used for direct speech ("She said, ''I will go.''"), titles of short works (articles, poems), and to indicate that a word is being used in a special way.', 'English', 'Writing', 'easy', 'secondary'),
('What is an "adverb"?', '["A word that modifies a verb, adjective, or another adverb", "A word that describes a noun", "A word that replaces a noun", "A word that connects sentences"]', 'A', 'An adverb modifies verbs, adjectives, or other adverbs, often indicating manner, time, place, or degree (e.g., quickly, very, here, often).', 'English', 'Grammar', 'easy', 'secondary'),
('What does the word "protagonist" mean?', '["The main character in a story", "The villain of a story", "A supporting character", "A narrator who is not part of the story"]', 'A', 'The protagonist is the main character of a story around whom the plot revolves. They face the central conflict and typically drive the narrative forward.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which sentence contains a split infinitive?', '["She wants to quickly finish her homework.", "She wants to finish her homework quickly.", "She quickly wants to finish homework.", "Finishing homework quickly is her goal."]', 'A', 'A split infinitive has an adverb placed between "to" and the verb: "to quickly finish." While widely accepted today, it is traditionally considered incorrect in formal writing.', 'English', 'Writing', 'hard', 'secondary'),
('What is the term for language that is not meant to be taken literally?', '["Figurative language", "Literal language", "Technical language", "Denotative language"]', 'A', 'Figurative language uses words in non-literal ways to convey meaning or create effects. Examples include metaphors, similes, hyperbole, and personification.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is an "antagonist"?', '["A character or force that opposes the protagonist", "The narrator of a story", "A minor character", "The hero of a story"]', 'A', 'The antagonist is the character or force that opposes the protagonist, creating conflict. The antagonist is often (but not always) a villain.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is the correct word choice: "The teacher asked the student to __ the lesson."', '["Review", "Revue", "Revue", "Re-view"]', 'A', '"Review" (to examine or study again) is the correct word. "Revue" is a type of theatrical entertainment, which doesn''t fit this context.', 'English', 'Vocabulary', 'easy', 'secondary'),
('Which of the following is an example of a metaphor?', '["Life is a journey.", "Life is like a journey.", "She ran as fast as a cheetah.", "He was sweating like a pig."]', 'A', 'A metaphor states one thing IS another (without "like" or "as"). "Life is a journey" directly equates life with a journey.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is a "clause" in grammar?', '["A group of words with a subject and a predicate", "A phrase without a verb", "A single word that expresses a complete thought", "A sentence connector"]', 'A', 'A clause is a group of words containing both a subject and a predicate. Independent clauses can stand alone; dependent clauses cannot.', 'English', 'Grammar', 'medium', 'secondary'),
('What is the term for repetition of the same ending sounds in words?', '["Rhyme", "Alliteration", "Assonance", "Consonance"]', 'A', 'Rhyme is the repetition of similar ending sounds in words (e.g., "moon" and "June"). End rhyme appears at line ends; internal rhyme appears within lines.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What does the word "ubiquitous" mean?', '["Appearing or found everywhere", "Extremely rare", "Invisible to the naked eye", "Extremely valuable"]', 'A', 'Ubiquitous means present, appearing, or found everywhere. "Smartphones are ubiquitous in modern life."', 'English', 'Vocabulary', 'hard', 'secondary'),
('Which sentence is grammatically correct?', '["Neither the students nor the teacher was present.", "Neither the students nor the teacher were present.", "Neither the students nor the teacher have been present.", "Neither the students nor the teachers is present."]', 'A', 'With "neither...nor," the verb agrees with the subject closest to it. "Teacher" (singular) is closest, so "was" is correct.', 'English', 'Grammar', 'hard', 'secondary'),
('What is a "paradox" in literature?', '["A seemingly contradictory statement that reveals a truth", "A logical fallacy", "An extreme exaggeration", "An impossible situation"]', 'A', 'A paradox is a statement that appears self-contradictory but reveals a deeper truth (e.g., "The more you know, the more you realize you don''t know").', 'English', 'Literary Devices', 'hard', 'secondary'),
('What is the correct word: "The audience was impressed by __ performance."', '["their", "there", "they''re", "its"]', 'A', '"Their" is the possessive pronoun showing ownership. "There" indicates place, "they''re" means "they are." The correct choice is "their performance."', 'English', 'Grammar', 'easy', 'secondary'),
('What is a "narrative hook"?', '["An opening technique to capture the reader''s immediate interest", "The conclusion of a story", "A plot twist at the midpoint", "A summary at the end"]', 'A', 'A narrative hook is an opening line or passage designed to immediately capture the reader''s interest and compel them to continue reading.', 'English', 'Writing', 'medium', 'secondary'),
('What is "diction" in writing?', '["The writer''s word choice", "The rhythm and meter of a poem", "The plot structure of a story", "The point of view used in a text"]', 'A', 'Diction refers to the choice and use of words in writing. Good diction involves selecting words appropriate to the audience, purpose, and style.', 'English', 'Writing', 'medium', 'secondary'),
('What is a "flashback" in a story?', '["A scene that interrupts the present narrative to show events from the past", "A hint about future events", "A sudden action in the story", "A fast-paced scene"]', 'A', 'A flashback (analepsis) is a narrative technique where the story momentarily moves back in time to show past events that provide context for the present story.', 'English', 'Literary Devices', 'easy', 'secondary'),
('What does the term "round character" mean?', '["A complex character with realistic, multiple traits who develops throughout the story", "A character who is perfect and has no flaws", "A character who appears in every scene", "A character who remains unchanged"]', 'A', 'A round character is complex and multidimensional, with a range of realistic traits and the potential for change and growth throughout the story.', 'English', 'Literary Devices', 'medium', 'secondary'),
('Which of the following is NOT a preposition?', '["Quickly", "Under", "Between", "During"]', 'A', '"Quickly" is an adverb, not a preposition. Prepositions show relationships between nouns: under, between, during, on, in, at, etc.', 'English', 'Grammar', 'easy', 'secondary'),
('What is the term for the lesson or message an author wants to convey in a story?', '["Theme", "Plot", "Conflict", "Setting"]', 'A', 'Theme is the central message, moral, or universal truth that an author communicates through a story. It is usually an abstract concept like love, justice, or courage.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which form of "lay/lie" is correct? "Yesterday, he __ on the couch all day."', '["Lay", "Lied", "Lain", "Lie"]', 'A', '"Lay" is the simple past tense of "lie" (to recline). To recline: lie/lay/lain. To place: lay/laid/laid. "He lay on the couch yesterday" is correct.', 'English', 'Grammar', 'hard', 'secondary'),
('What does the Latin root "voc" or "vok" mean?', '["Voice or call", "Life", "Light", "Truth"]', 'A', 'The Latin root "voc/vok" means voice or call. Words derived from it include: vocal, invoke, vocabulary, advocate, vocation.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is "stream of consciousness" in literature?', '["A narrative technique that depicts the flow of thoughts and feelings of a character", "A story told in strict chronological order", "A story told from multiple perspectives simultaneously", "A story without a clear plot"]', 'A', 'Stream of consciousness is a narrative technique that presents a character''s continuous flow of thoughts, feelings, and perceptions in an unstructured manner (used by James Joyce, Virginia Woolf).', 'English', 'Literary Devices', 'hard', 'secondary');
